#!/usr/bin/env python3
"""Generate the active deduction-first strategic task queue."""
from __future__ import annotations
from pathlib import Path
from report_link_utils import markdown_link
ROOT=Path(__file__).resolve().parents[1]; OUT=ROOT/'docs/planning/next-actions.md'; STATUS=ROOT/'docs/reports/project-status-generated.md'; GAP=ROOT/'docs/reports/research-gap-report.md'
TASKS=[
{'id':'STRATEGIC-001','priority':'high','title':'Execute the W4 S_core formal negative controls','why':'All 24 construction lemmas are proved and eight obstruction hypotheses are refuted. The remaining scientific blocker is OBS-SC-010: prove that NC-01 through NC-10 are rejected by the frozen preservation recovery semantics coherence uniformity composition and machinery obligations, or preserve any valid countermodel.','affected':['docs/research/s-core-construction-obstruction-ledger-v1.0.md','theory/evaluation/s-core-construction-obstruction-ledger.json','docs/methodology/negative-control-suite-v1.0.md','theory/evaluation/faithful-representation-specification-v1.0.json'],'outcome':'A versioned formal negative-control package resolving OBS-SC-010 and the global Nontrivial conjunct without changing the frozen representation definition.','risk':'high','branch':'research/prove-s-core-w4-negative-controls','pr':'Prove S_core W4 formal negative controls'},
{'id':'STRATEGIC-002','priority':'high','title':'Assemble the finite-core theorem or strongest obstruction','why':'Once OBS-SC-010 is resolved, ASM-SC-001 through ASM-SC-003 are the only remaining obligations. They must assemble the common schema arbitrary-episode witness and strongest justified finite-core conclusion without promoting S_core to S_IRD.','affected':['docs/research/s-core-construction-obstruction-ledger-v1.0.md','theory/evaluation/s-core-construction-obstruction-ledger.json','theory/evaluation/thm-target-001.json','theory/evaluation/central-claim-registry.json'],'outcome':'A complete scoped theorem formal countermodel proper-subclass theorem impossibility result or explicit unresolved result with every premise dependency and nonclaim named.','risk':'high','branch':'research/assemble-s-core-result','pr':'Assemble S_core theorem or obstruction'}]
def nav_links(): return [f"- README Command Center: {markdown_link(ROOT/'README.md',OUT)}",f"- Project Status: {markdown_link(STATUS,OUT)}",f"- Research Gaps: {markdown_link(GAP,OUT)}",f"- Next Actions: {markdown_link(OUT,OUT)}"]
def main()->int:
    ids=[x['id'] for x in TASKS]; assert len(ids)==len(set(ids))
    lines=['# Next Actions','','## Navigation','',*nav_links(),'','Generated by `python tools/generate_next_tasks.py` under the deduction-first strategic priority. THM-TARGET-001, FAITHFUL-REP-001, P8-ROLE-001, and SCORE-LEMMA-LEDGER-001 remain frozen. SCORE-W0-PROOF-001 through SCORE-W3-PROOF-001 establish all 24 construction lemmas, one source boundary, and eight refuted obstruction hypotheses; four obligations remain and W4 is active. Research gaps remain available but do not automatically enter the central queue.','','## Ranked Next Actions','']
    for t in TASKS:
        affected=[markdown_link(ROOT/p,OUT) for p in t['affected']]
        lines += [f"### {t['id']}: {t['title']}",'','- Source: deduction-first strategic priority',f"- Priority: {t['priority']}",f"- Why it matters: {t['why']}",'- Affected files:',*[f'  - {x}' for x in affected],f"- Expected outcome: {t['outcome']}",f"- Risk level: {t['risk']}",f"- Suggested branch name: `{t['branch']}`",f"- Suggested PR title: `{t['pr']}`",'']
    lines += ['## Maintainer Task Briefs','']
    for t in TASKS:
        lines += [f"### Task brief for {t['id']}",'','```markdown',f"Create branch `{t['branch']}`.",f"Scope: {t['title']}.",'Preserve THM-TARGET-001, FAITHFUL-REP-001, P8-ROLE-001, SCORE-LEMMA-LEDGER-001, SCORE-W0-PROOF-001 through SCORE-W3-PROOF-001, all failures and unresolved obligations, and every nonclaim.','Do not mark an obligation resolved without a versioned proof artifact and dependency audit. Do not claim S_IRD universality, necessity, minimality, proof-assistant verification, actual-process correspondence, or independent validation without registered evidence.','Validation commands:','- `make research-check`','- `make health-fast`',f"PR title: `{t['pr']}`",'```','']
    lines += ['## Navigation','',*nav_links()]
    OUT.write_text('\n'.join(lines)+'\n',encoding='utf-8'); print(f'{OUT.relative_to(ROOT)} tasks={len(TASKS)}'); return 0
if __name__=='__main__': raise SystemExit(main())
